ALTER TABLE bank_receipt ADD COLUMN IF NOT EXISTS collection_record_id BIGINT;
CREATE UNIQUE INDEX IF NOT EXISTS uk_bank_receipt_collection ON bank_receipt(tenant_id,collection_record_id);
CREATE TABLE IF NOT EXISTS collection_forecast(id BIGINT PRIMARY KEY,tenant_id BIGINT DEFAULT 0 NOT NULL,project_id BIGINT NOT NULL,contract_id BIGINT,forecast_date DATE NOT NULL,scenario VARCHAR(32) NOT NULL,expected_amount DECIMAL(18,2) NOT NULL,confidence DECIMAL(5,4) DEFAULT 1 NOT NULL,source_type VARCHAR(32) NOT NULL,source_id BIGINT,status VARCHAR(32) DEFAULT 'ACTIVE' NOT NULL,version INT DEFAULT 0 NOT NULL,created_by BIGINT,created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP NOT NULL,CONSTRAINT fk_collection_forecast_project FOREIGN KEY(project_id) REFERENCES pm_project(id),CONSTRAINT fk_collection_forecast_contract FOREIGN KEY(contract_id) REFERENCES ct_contract(id));
CREATE TABLE IF NOT EXISTS customer_credit_profile(id BIGINT PRIMARY KEY,tenant_id BIGINT DEFAULT 0 NOT NULL,customer_id BIGINT NOT NULL,credit_limit DECIMAL(18,2) DEFAULT 0 NOT NULL,risk_level VARCHAR(16) DEFAULT 'NORMAL' NOT NULL,dso_days INT DEFAULT 0 NOT NULL,overdue_amount DECIMAL(18,2) DEFAULT 0 NOT NULL,score DECIMAL(8,2) DEFAULT 100 NOT NULL,formula_version VARCHAR(64) DEFAULT 'CUSTOMER_CREDIT_V1' NOT NULL,refreshed_at TIMESTAMP NOT NULL,CONSTRAINT fk_customer_credit_partner FOREIGN KEY(customer_id) REFERENCES md_partner(id));
CREATE UNIQUE INDEX IF NOT EXISTS uk_customer_credit ON customer_credit_profile(tenant_id,customer_id);
CREATE TABLE IF NOT EXISTS revenue_external_sync(id BIGINT PRIMARY KEY,tenant_id BIGINT DEFAULT 0 NOT NULL,endpoint_id BIGINT NOT NULL,business_type VARCHAR(64) NOT NULL,business_id BIGINT NOT NULL,message_id BIGINT,sync_status VARCHAR(32) NOT NULL,idempotency_key VARCHAR(128) NOT NULL,last_error VARCHAR(1000),synced_at TIMESTAMP,created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP NOT NULL,CONSTRAINT fk_revenue_sync_endpoint FOREIGN KEY(endpoint_id) REFERENCES finance_integration_endpoint(id),CONSTRAINT fk_revenue_sync_message FOREIGN KEY(message_id) REFERENCES finance_integration_message(id));
CREATE UNIQUE INDEX IF NOT EXISTS uk_revenue_external_sync ON revenue_external_sync(tenant_id,endpoint_id,idempotency_key);
